#include <stdio.h>
#include <math.h>

int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int x[N], y[N], r[N];
    for (int i = 0; i < N; i++) {
        scanf("%d %d %d", &x[i], &y[i], &r[i]);
    }
    for (int i = 0; i < Q; i++) {
        int x1, y1, x2, y2;
        scanf("%d %d %d %d", &x1, &y1, &x2, &y2);
        double area = 0;
        for (int j = 0; j < N; j++) {
            double dx = x[j] - x1;
            double dy = y[j] - y1;
            double distance = sqrt(dx * dx + dy * dy);
            if (distance <= r[j]) {
                // calculate the area of the intersection
                double angle = acos(distance / r[j]);
                area += 0.5 * r[j] * r[j] * (2 * angle - sin(2 * angle));
            }
        }
        printf("%.10f\n", area);
    }
    return 0;
}

